import React from "react";
import { useLocation, useLoaderData } from "react-router";

// @ts-ignore - virtual module generated by access control plugin
import { pluginPages, AccessControlProvider } from "virtual:xyd-plugin-pages";

/**
 * Loader: resolves seoTags from the page module at pre-render time.
 * This ensures meta tags appear in the HTML source (view-source).
 */
export async function loader({ request }: { request: any }) {
    const url = new URL(request.url);
    const pageEntry = pluginPages[url.pathname];

    if (!pageEntry?.seoTags) {
        return { seoTags: null };
    }

    const result = pageEntry.seoTags();
    const tags = result instanceof Promise ? await result : result;
    return { seoTags: tags };
}

/**
 * Meta: converts seoTags into React Router meta tags for pre-rendering.
 * Same pattern as xyd-plugin-docs/page.tsx meta export.
 */
export function meta(props: any) {
    const tags = props?.data?.seoTags;
    if (!tags) return [];

    const metaTags: any[] = [];

    for (const [key, value] of Object.entries(tags)) {
        if (!value) continue;

        if (key === "title") {
            metaTags.push({ title: value });
            continue;
        }

        if (key.startsWith("og:") || key.startsWith("article:") || key.startsWith("music:") || key.startsWith("video:") || key.startsWith("book:") || key.startsWith("profile:")) {
            metaTags.push({ property: key, content: value });
        } else {
            metaTags.push({ name: key, content: value });
        }
    }

    return metaTags;
}

/**
 * Renders a plugin-registered custom page.
 * Wraps with AccessControlProvider so useAccessControl() works.
 */
export default function PluginPage() {
    const location = useLocation();
    const pageEntry = pluginPages[location.pathname];

    if (!pageEntry) {
        return (
            <div style={{ padding: "48px 24px", textAlign: "center", color: "var(--dark48, #6e6e80)" }}>
                Page not found.
            </div>
        );
    }

    const PageComponent = pageEntry.component || pageEntry;

    if (AccessControlProvider) {
        return (
            <AccessControlProvider>
                <PageComponent />
            </AccessControlProvider>
        );
    }

    return <PageComponent />;
}
